{"command": "cat wiki/89ee4db6-0626-4636-8c66-49a575d05832/manifest.json 2>/dev/null | python3 -c "
import json,sys
d=json.load(sys.stdin)
docs = d.get('documents',[])
# 按folderPath分组，查看有哪些分类
folders = {}
for doc in docs:
    fp = doc.get('folderPath','/')
    if fp not in folders:
        folders[fp] = []
    folders[fp].append(doc.get('fileName',''))

for folder, files in sorted(folders.items()):
    print(f'Folder: {folder}')
    print(f'  文件数: {len(files)}')
    for f in files[:5]:
        print(f'    - {f}')
    if len(files) > 5:
        print(f'    ... 还有{len(files)-5}个文件')
    print()
""}

